INSERT INTO article_translations (article_id, lang, title, summary, body_md, source, status) VALUES
('b2000000-0000-0000-0000-000000000001','ru','Спорт: главное на сегодня','Ключевые темы рубрики «Спорт» в одном материале.',$md$Обзор ключевых спортивных событий недели: результаты матчей, турнирные расклады и имена, о которых говорят болельщики.

Следим за тем, как выступают казахстанские команды и атлеты на внутренней и международной аренах.$md$,'human','ready'),
('b2000000-0000-0000-0000-000000000002','ru','Общество: главное на сегодня','Ключевые темы рубрики «Общество» в одном материале.',$md$Что происходит в жизни людей: образование, здоровье, семья и повседневные заботы, которые редко попадают в заголовки, но касаются каждого.

Собираем истории и данные, которые помогают понять, чем живёт общество сегодня.$md$,'human','ready'),
('b2000000-0000-0000-0000-000000000003','ru','Политика: главное на сегодня','Ключевые темы рубрики «Политика» в одном материале.',$md$Разбор решений, которые влияют на всех: кто их принимает, в чьих интересах и что стоит за официальными формулировками.

Политика простыми словами — без лозунгов и с уважением к читателю.$md$,'human','ready'),
('b2000000-0000-0000-0000-000000000004','ru','Экономика: главное на сегодня','Ключевые темы рубрики «Экономика» в одном материале.',$md$Цены, зарплаты, бизнес и бюджет — экономика касается кошелька каждого. Объясняем, что стоит за цифрами.

Без сложного жаргона: только то, что действительно важно понимать.$md$,'human','ready'),
('b2000000-0000-0000-0000-000000000005','ru','Культура: главное на сегодня','Ключевые темы рубрики «Культура» в одном материале.',$md$Литература, кино и музыка формируют то, как мы видим себя. Рассказываем о новых именах и заметных событиях культурной жизни.

Особое внимание — казахскоязычному творчеству и его новому поколению.$md$,'human','ready'),
('b2000000-0000-0000-0000-000000000006','ru','Технологии: главное на сегодня','Ключевые темы рубрики «Технологии» в одном материале.',$md$Интернет, искусственный интеллект и наука меняют повседневность быстрее, чем мы успеваем осмыслить. Помогаем разобраться.

Без хайпа: что из технологий реально работает и зачем это вам.$md$,'human','ready'),
('b2000000-0000-0000-0000-000000000007','ru','Мнение: главное на сегодня','Ключевые темы рубрики «Мнение» в одном материале.',$md$Мнения и колонки: авторы спорят, сомневаются и предлагают взглянуть на привычное под другим углом.

Здесь важна не громкость, а аргумент.$md$,'human','ready'),
('b2000000-0000-0000-0000-000000000008','ru','Мир: главное на сегодня','Ключевые темы рубрики «Мир» в одном материале.',$md$Что происходит за пределами страны и почему это касается нас: Центральная Азия, Европа, Азия и мир в целом.

Международные события — через призму того, что они значат для Казахстана.$md$,'human','ready'),
('b2000000-0000-0000-0000-000000000009','ru','Футбол: обзор дня','Что важно знать сегодня в теме «Футбол».',$md$Итоги последних матчей, форма ведущих клубов и сборной. Разбираем, кто набирает ход, а кому предстоит серьёзная работа над ошибками.$md$,'human','ready'),
('b2000000-0000-0000-0000-00000000000a','ru','Бокс: обзор дня','Что важно знать сегодня в теме «Бокс».',$md$Бокс остаётся визитной карточкой казахстанского спорта. Следим за поединками, титульными боями и новым поколением бойцов.$md$,'human','ready'),
('b2000000-0000-0000-0000-00000000000b','ru','Хоккей: обзор дня','Что важно знать сегодня в теме «Хоккей».',$md$Хоккейный сезон в разгаре: результаты, лидеры и борьба за плей-офф. Смотрим, как складывается турнирная таблица.$md$,'human','ready'),
('b2000000-0000-0000-0000-00000000000c','ru','Лёгкая атлетика: обзор дня','Что важно знать сегодня в теме «Лёгкая атлетика».',$md$Лёгкая атлетика — школа характера. Рассказываем о рекордах, стартах и спортсменах, которые задают темп.$md$,'human','ready'),
('b2000000-0000-0000-0000-00000000000d','ru','Образование: обзор дня','Что важно знать сегодня в теме «Образование».',$md$Школа и университет определяют будущее. Обсуждаем доступность образования, нагрузку на учителей и то, что волнует родителей.$md$,'human','ready'),
('b2000000-0000-0000-0000-00000000000e','ru','Здоровье: обзор дня','Что важно знать сегодня в теме «Здоровье».',$md$Здоровье — то, что нельзя купить задним числом. Говорим о доступности медицины, профилактике и заботе о себе.$md$,'human','ready'),
('b2000000-0000-0000-0000-00000000000f','ru','Семья: обзор дня','Что важно знать сегодня в теме «Семья».',$md$Семья остаётся опорой в любые времена. Практические темы: воспитание, поддержка и баланс между работой и домом.$md$,'human','ready'),
('b2000000-0000-0000-0000-000000000010','ru','Выборы: обзор дня','Что важно знать сегодня в теме «Выборы».',$md$Выборы — момент, когда голос каждого имеет вес. Объясняем процедуры, права избирателя и то, как проверять результаты.$md$,'human','ready'),
('b2000000-0000-0000-0000-000000000011','ru','Парламент: обзор дня','Что важно знать сегодня в теме «Парламент».',$md$Парламент принимает законы, которые касаются всех. Следим за инициативами и объясняем их простым языком.$md$,'human','ready'),
('b2000000-0000-0000-0000-000000000012','ru','Регионы: обзор дня','Что важно знать сегодня в теме «Регионы».',$md$Жизнь страны не заканчивается в столице. Рассказываем о проблемах и достижениях регионов — от инфраструктуры до местных инициатив.$md$,'human','ready'),
('b2000000-0000-0000-0000-000000000013','ru','Цены: обзор дня','Что важно знать сегодня в теме «Цены».',$md$Цены на продукты и услуги — самый чувствительный индикатор экономики. Отслеживаем, что дорожает и почему.$md$,'human','ready'),
('b2000000-0000-0000-0000-000000000014','ru','Бизнес: обзор дня','Что важно знать сегодня в теме «Бизнес».',$md$Малый и средний бизнес — двигатель занятости. Разбираем условия для предпринимателей и истории тех, кто рискнул.$md$,'human','ready'),
('b2000000-0000-0000-0000-000000000015','ru','Энергетика: обзор дня','Что важно знать сегодня в теме «Энергетика».',$md$Энергетика определяет тарифы и устойчивость экономики. Объясняем, откуда берётся электричество и сколько оно стоит.$md$,'human','ready'),
('b2000000-0000-0000-0000-000000000016','ru','Литература: обзор дня','Что важно знать сегодня в теме «Литература».',$md$Новая казахская проза ищет свой голос. Рассказываем, что читать и почему литература возвращает языку престиж.$md$,'human','ready'),
('b2000000-0000-0000-0000-000000000017','ru','Кино: обзор дня','Что важно знать сегодня в теме «Кино».',$md$Отечественное кино взрослеет. Обсуждаем премьеры, режиссёров и то, как экран отражает нашу жизнь.$md$,'human','ready'),
('b2000000-0000-0000-0000-000000000018','ru','Музыка: обзор дня','Что важно знать сегодня в теме «Музыка».',$md$От традиции до современной сцены — музыка объединяет поколения. Знакомим с новыми именами и заметными релизами.$md$,'human','ready'),
('b2000000-0000-0000-0000-000000000019','ru','Интернет: обзор дня','Что важно знать сегодня в теме «Интернет».',$md$Интернет стал базовой инфраструктурой жизни. Говорим о доступе, скорости и о том, как сохранять связь при сбоях.$md$,'human','ready'),
('b2000000-0000-0000-0000-00000000001a','ru','ИИ: обзор дня','Что важно знать сегодня в теме «ИИ».',$md$Искусственный интеллект уже помогает писать, переводить и анализировать. Объясняем, где он полезен, а где стоит быть осторожным.$md$,'human','ready'),
('b2000000-0000-0000-0000-00000000001b','ru','Наука: обзор дня','Что важно знать сегодня в теме «Наука».',$md$Наука — это любопытство, доведённое до метода. Рассказываем об исследованиях и открытиях понятным языком.$md$,'human','ready'),
('b2000000-0000-0000-0000-00000000001c','ru','Колонка: обзор дня','Что важно знать сегодня в теме «Колонка».',$md$Авторская колонка: личный взгляд на события, за который автор готов отвечать. Приглашаем к разговору, а не к согласию.$md$,'human','ready'),
('b2000000-0000-0000-0000-00000000001d','ru','Дискуссия: обзор дня','Что важно знать сегодня в теме «Дискуссия».',$md$Дискуссия — способ проверить идею на прочность. Сталкиваем аргументы и даём слово разным сторонам.$md$,'human','ready'),
('b2000000-0000-0000-0000-00000000001e','ru','Центральная Азия: обзор дня','Что важно знать сегодня в теме «Центральная Азия».',$md$Центральная Азия связана общей историей и будущим. Следим за тем, что происходит у соседей и что это значит для региона.$md$,'human','ready'),
('b2000000-0000-0000-0000-00000000001f','ru','Европа: обзор дня','Что важно знать сегодня в теме «Европа».',$md$События в Европе влияют на мировую повестку и на нас. Объясняем ключевые процессы без упрощений.$md$,'human','ready'),
('b2000000-0000-0000-0000-000000000020','ru','Азия: обзор дня','Что важно знать сегодня в теме «Азия».',$md$Азия — центр мировой экономики и политики XXI века. Рассказываем о трендах, которые формируют завтрашний день.$md$,'human','ready')
ON CONFLICT (article_id, lang) DO NOTHING;
